import anthropic, json

client = anthropic.Anthropic()

def run_claude_agent(
    user_message: str,
    tools: list,
    system: str | None = None,
    max_turns: int = 15,
) -> str:
    messages = [{"role": "user", "content": user_message}]
    kwargs = {"tools": tools}
    if system:
        kwargs["system"] = system

    for turn in range(max_turns):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            messages=messages,
            **kwargs,
        )
        # Append full assistant turn (may contain text + tool_use blocks)
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            texts = [b.text for b in response.content if hasattr(b, "text")]
            return " ".join(texts).strip()

        if response.stop_reason == "max_tokens":
            raise RuntimeError("Response truncated — increase max_tokens")

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type != "tool_use":
                    continue
                try:
                    result = dispatch_tool(block.name, block.input)
                except Exception as exc:
                    result = json.dumps({"error": str(exc)})
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "is_error": True,
                        "content": result,
                    })
                    continue
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })
            messages.append({"role": "user", "content": tool_results})
            continue

        raise RuntimeError(f"Unhandled stop_reason: {response.stop_reason}")

    raise RuntimeError(f"Agent exceeded {max_turns} turns")

def inspect_response(response) -> None:
    print(f"stop_reason: {response.stop_reason}")
    print(f"usage: {response.usage.input_tokens} in / {response.usage.output_tokens} out")
    for i, block in enumerate(response.content):
        if block.type == "text":
            print(f"  [{i}] text: {block.text[:80]!r}")
        elif block.type == "tool_use":
            print(f"  [{i}] tool_use: {block.name}({block.input}) id={block.id[:16]}")
        else:
            print(f"  [{i}] unknown type: {block.type}")

