import anthropic

client = anthropic.Anthropic()

TOOLS = [
    {
        "name": "get_price",
        "description": "Fetch the current price of a stock ticker.",
        "input_schema": {
            "type": "object",
            "properties": {"ticker": {"type": "string"}},
            "required": ["ticker"]
        }
    }
]

def fake_get_price(ticker: str) -> dict:
    prices = {"AAPL": 195.42, "MSFT": 415.20, "GOOG": 178.90}
    if ticker in prices:
        return {"ticker": ticker, "price": prices[ticker], "currency": "USD"}
    return {"error": f"Unknown ticker: {ticker}"}

def run_with_history(user_query: str) -> str:
    messages = [{"role": "user", "content": user_query}]

    while True:
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            tools=TOOLS,
            messages=messages
        )

        # Append the full assistant turn (text + tool calls) to history
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Extract and return the final text
            for block in response.content:
                if block.type == "text":
                    return block.text
            return ""

        # Handle tool calls and append results in one user turn
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = fake_get_price(**block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result)
                })

        messages.append({"role": "user", "content": tool_results})

