import anthropic, json

client = anthropic.Anthropic()

TOOLS = [
    {
        "name": "summarize_text",
        "description": "Summarize the provided text.",
        "input_schema": {
            "type": "object",
            "properties": {
                "text": {"type": "string", "description": "Text to summarize"},
                "max_sentences": {"type": "integer", "description": "Maximum sentences"}
            },
            "required": ["text", "max_sentences"]
        }
    }
]

def fake_summarize(text: str, max_sentences: int) -> str:
    sentences = text.split(". ")[:max_sentences]
    return ". ".join(sentences) + ("." if not sentences[-1].endswith(".") else "")

with client.messages.stream(
    model="claude-sonnet-4-6",
    max_tokens=1024,
    tools=TOOLS,
    messages=[{"role": "user", "content": "Summarize this in 2 sentences: 'The quick brown fox jumps over the lazy dog. It was a beautiful morning. The sun shone brightly.'"}]
) as stream:
    for event in stream:
        pass  # Stream events flow; we just collect them

    final = stream.get_final_message()

for block in final.content:
    if block.type == "tool_use":
        result = fake_summarize(**block.input)
        print(f"Summary: {result}")

from pydantic import BaseModel, ValidationError
import anthropic, json

client = anthropic.Anthropic()

class SearchArgs(BaseModel):
    query: str
    max_results: int = 10
    date_filter: str | None = None  # e.g. "2024-01-01"

TOOL = {
    "name": "web_search",
    "description": "Search the web for information.",
    "input_schema": {
        "type": "object",
        "properties": {
            "query": {"type": "string"},
            "max_results": {"type": "integer", "minimum": 1, "maximum": 50},
            "date_filter": {"type": "string", "description": "ISO date string"}
        },
        "required": ["query"]
    }
}

def safe_dispatch(block) -> dict:
    try:
        args = SearchArgs(**block.input)
    except ValidationError as e:
        return {"error": f"Invalid tool arguments: {e.errors()}"}

    # args is now a typed, validated object
    return {"results": [f"Result for: {args.query}"], "count": args.max_results}

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=512,
    tools=[TOOL],
    messages=[{"role": "user", "content": "Search for Python async patterns, limit 5."}]
)

for block in response.content:
    if block.type == "tool_use":
        result = safe_dispatch(block)
        print(json.dumps(result, indent=2))

import anthropic, json, concurrent.futures

client = anthropic.Anthropic()

def call_tool(name: str, args: dict) -> str:
    """Dispatch to the right handler and return JSON string."""    if name == "get_weather":
        return json.dumps({"city": args["city"], "temp_c": 22, "condition": "Sunny"})
    if name == "get_news":
        return json.dumps({"topic": args["topic"], "headlines": ["Headline 1", "Headline 2"]})
    return json.dumps({"error": f"Unknown tool: {name}"})

TOOLS = [
    {"name": "get_weather", "description": "Current weather for a city.",
     "input_schema": {"type": "object", "properties": {"city": {"type": "string"}}, "required": ["city"]}},
    {"name": "get_news",   "description": "Latest headlines on a topic.",
     "input_schema": {"type": "object", "properties": {"topic": {"type": "string"}}, "required": ["topic"]}},
]

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=1024,
    tools=TOOLS,
    messages=[{"role": "user", "content": "What's the weather in Paris and the latest AI news?"}]
)

if response.stop_reason == "tool_use":
    tool_blocks = [b for b in response.content if b.type == "tool_use"]

    # Execute all calls in parallel
    with concurrent.futures.ThreadPoolExecutor() as executor:
        futures = {b.id: executor.submit(call_tool, b.name, b.input) for b in tool_blocks}

    tool_results = [
        {"type": "tool_result", "tool_use_id": bid, "content": fut.result()}
        for bid, fut in futures.items()
    ]

    # Append assistant turn + all results in one user turn
    followup = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        tools=TOOLS,
        messages=[
            {"role": "user", "content": "What's the weather in Paris and the latest AI news?"},
            {"role": "assistant", "content": response.content},
            {"role": "user", "content": tool_results}
        ]
    )
    for block in followup.content:
        if block.type == "text":
            print(block.text)

from dataclasses import dataclass, field
import anthropic, json

@dataclass
class UsageTracker:
    input_tokens: int = 0
    output_tokens: int = 0
    turns: int = 0

    def record(self, usage) -> None:
        self.input_tokens  += usage.input_tokens
        self.output_tokens += usage.output_tokens
        self.turns         += 1

    @property
    def total_tokens(self) -> int:
        return self.input_tokens + self.output_tokens

    def report(self) -> str:
        return (
            f"Turns: {self.turns} | "
            f"Input: {self.input_tokens} | "
            f"Output: {self.output_tokens} | "
            f"Total: {self.total_tokens}"
        )

client = anthropic.Anthropic()
tracker = UsageTracker()

TOOLS = [
    {"name": "add", "description": "Add two numbers.",
     "input_schema": {"type": "object",
                      "properties": {"a": {"type": "number"}, "b": {"type": "number"}},
                      "required": ["a", "b"]}}
]

messages = [{"role": "user", "content": "What is 123 + 456?"}]

while True:
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=256,
        tools=TOOLS,
        messages=messages
    )
    tracker.record(response.usage)
    messages.append({"role": "assistant", "content": response.content})

    if response.stop_reason == "end_turn":
        for block in response.content:
            if block.type == "text":
                print(block.text)
        break

    results = []
    for block in response.content:
        if block.type == "tool_use":
            result = {"sum": block.input["a"] + block.input["b"]}
            results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": json.dumps(result)
            })
    messages.append({"role": "user", "content": results})

print(tracker.report())
